import React, { useState } from 'react';
import { Lead, Note, LeadStatus } from '../types';
import { X, Mail, Phone, Calendar, MapPin, Brain, Save, Send, Loader2, FileText } from 'lucide-react';
import { generateEmailDraft, summarizeLead } from '../services/geminiService';

interface LeadDetailProps {
  lead: Lead;
  onClose: () => void;
  onUpdateLead: (updatedLead: Lead) => void;
}

export const LeadDetail: React.FC<LeadDetailProps> = ({ lead, onClose, onUpdateLead }) => {
  const [activeTab, setActiveTab] = useState<'info' | 'notes' | 'ai'>('info');
  const [newNote, setNewNote] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiResponse, setAiResponse] = useState<string>('');
  const [aiActionType, setAiActionType] = useState<string>('');

  const handleStatusChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    onUpdateLead({ ...lead, status: e.target.value as LeadStatus });
  };

  const handleAddNote = () => {
    if (!newNote.trim()) return;
    const note: Note = {
      id: Date.now().toString(),
      content: newNote,
      date: new Date().toLocaleDateString(),
      author: 'You',
    };
    onUpdateLead({ ...lead, notes: [note, ...lead.notes] });
    setNewNote('');
  };

  const handleGenerateEmail = async (type: 'intro' | 'followup' | 'estimate' | 'closing') => {
    setIsGenerating(true);
    setAiActionType(`Generating ${type} email...`);
    const draft = await generateEmailDraft(lead, type);
    setAiResponse(draft);
    setIsGenerating(false);
  };

  const handleSummarize = async () => {
    setIsGenerating(true);
    setAiActionType('Summarizing lead...');
    const summary = await summarizeLead(lead);
    setAiResponse(summary);
    setIsGenerating(false);
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4 z-50 animate-in fade-in duration-200">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl h-[90vh] flex flex-col overflow-hidden">

        {/* Header */}
        <div className="p-6 border-b border-slate-100 flex justify-between items-start bg-slate-50">
          <div>
            <h2 className="text-2xl font-bold text-slate-800">{lead.firstName} {lead.lastName}</h2>
            <div className="flex items-center text-slate-500 mt-1">
              <MapPin size={16} className="mr-1" />
              {lead.address}
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-200 rounded-full transition">
            <X size={24} className="text-slate-500" />
          </button>
        </div>

        <div className="flex flex-1 overflow-hidden">
          {/* Sidebar Info */}
          <div className="w-1/3 bg-slate-50 p-6 border-r border-slate-100 overflow-y-auto hidden md:block">
            <div className="space-y-6">
              <div>
                <label className="block text-xs font-semibold text-slate-400 uppercase tracking-wider mb-1">Status</label>
                <select 
                  value={lead.status} 
                  onChange={handleStatusChange}
                  className="w-full p-2 border border-slate-300 rounded-lg bg-white focus:ring-2 focus:ring-blue-500 outline-none"
                >
                  <option value="New">New Lead</option>
                  <option value="Contacted">Contacted</option>
                  <option value="Estimate Sent">Estimate Sent</option>
                  <option value="Scheduled">Scheduled</option>
                  <option value="In Progress">In Progress</option>
                  <option value="Completed">Completed</option>
                  <option value="Lost">Lost</option>
                </select>
              </div>

              <div>
                <label className="block text-xs font-semibold text-slate-400 uppercase tracking-wider mb-1">Contact</label>
                <div className="flex items-center text-slate-700 mb-2">
                  <Mail size={16} className="mr-2 text-blue-500" />
                  <a href={`mailto:${lead.email}`} className="hover:underline text-sm truncate">{lead.email}</a>
                </div>
                <div className="flex items-center text-slate-700">
                  <Phone size={16} className="mr-2 text-blue-500" />
                  <span className="text-sm">{lead.phone}</span>
                </div>
              </div>

              <div>
                <label className="block text-xs font-semibold text-slate-400 uppercase tracking-wider mb-1">Project Details</label>
                <div className="bg-white p-3 rounded-lg border border-slate-200 space-y-2">
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-500">Value:</span>
                    <span className="font-semibold text-green-600">${lead.estimatedValue.toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-500">Roof Type:</span>
                    <span className="font-medium text-slate-700">{lead.roofType}</span>
                  </div>
                   <div className="flex justify-between text-sm">
                    <span className="text-slate-500">Last Contact:</span>
                    <span className="font-medium text-slate-700">{lead.lastContact}</span>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Main Content Area */}
          <div className="flex-1 flex flex-col bg-white">
            {/* Tabs */}
            <div className="flex border-b border-slate-100">
              <button 
                onClick={() => setActiveTab('info')}
                className={`flex-1 py-4 text-sm font-medium border-b-2 transition ${activeTab === 'info' ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
              >
                Overview
              </button>
              <button 
                onClick={() => setActiveTab('notes')}
                className={`flex-1 py-4 text-sm font-medium border-b-2 transition ${activeTab === 'notes' ? 'border-blue-500 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
              >
                Notes & Timeline
              </button>
              <button 
                onClick={() => setActiveTab('ai')}
                className={`flex-1 py-4 text-sm font-medium border-b-2 transition ${activeTab === 'ai' ? 'border-purple-500 text-purple-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
              >
                <div className="flex items-center justify-center">
                  <Brain size={16} className="mr-2" />
                  AI Assistant
                </div>
              </button>
            </div>

            {/* Tab Content */}
            <div className="flex-1 overflow-y-auto p-6 bg-slate-50/50">

              {activeTab === 'info' && (
                <div className="space-y-6">
                  {/* Mobile Only Info Block */}
                  <div className="md:hidden space-y-4 bg-white p-4 rounded-lg border border-slate-200">
                     <h3 className="font-semibold text-slate-800">Quick Info</h3>
                     <p className="text-sm text-slate-600"><span className="font-medium">Phone:</span> {lead.phone}</p>
                     <p className="text-sm text-slate-600"><span className="font-medium">Email:</span> {lead.email}</p>
                     <p className="text-sm text-slate-600"><span className="font-medium">Value:</span> ${lead.estimatedValue}</p>
                  </div>

                  <div className="bg-blue-50 border border-blue-100 p-4 rounded-lg">
                    <h3 className="text-blue-800 font-semibold mb-2">Next Steps</h3>
                    <p className="text-sm text-blue-600">
                      This lead is currently in <span className="font-bold">{lead.status}</span> status. 
                      {lead.status === 'New' && " Consider generating an introduction email from the AI Assistant tab."}
                      {lead.status === 'Estimate Sent' && " Follow up to answer any questions about the proposal."}
                      {lead.status === 'Completed' && " Send a closing email to request a review."}
                    </p>
                  </div>
                </div>
              )}

              {activeTab === 'notes' && (
                <div className="flex flex-col h-full">
                  <div className="flex-1 space-y-4 mb-4">
                    {lead.notes.length === 0 ? (
                      <p className="text-center text-slate-400 mt-10">No notes yet.</p>
                    ) : (
                      lead.notes.map((note) => (
                        <div key={note.id} className="bg-white p-4 rounded-lg shadow-sm border border-slate-200">
                          <p className="text-slate-700 whitespace-pre-wrap">{note.content}</p>
                          <div className="flex justify-between items-center mt-3 text-xs text-slate-400">
                            <span>{note.author}</span>
                            <span>{note.date}</span>
                          </div>
                        </div>
                      ))
                    )}
                  </div>
                  <div className="bg-white p-4 rounded-lg border border-slate-200 shadow-sm mt-auto">
                    <textarea 
                      value={newNote}
                      onChange={(e) => setNewNote(e.target.value)}
                      placeholder="Add a new note..."
                      className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none h-24 text-sm"
                    />
                    <div className="flex justify-end mt-2">
                      <button 
                        onClick={handleAddNote}
                        className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-sm font-medium flex items-center transition"
                      >
                        <Save size={16} className="mr-2" />
                        Save Note
                      </button>
                    </div>
                  </div>
                </div>
              )}

              {activeTab === 'ai' && (
                <div className="space-y-6">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <button 
                      onClick={() => handleGenerateEmail('intro')}
                      disabled={isGenerating}
                      className="p-4 bg-white border border-slate-200 rounded-lg hover:border-purple-300 hover:bg-purple-50 transition text-left group"
                    >
                      <h4 className="font-semibold text-slate-700 group-hover:text-purple-700 flex items-center">
                        <Mail size={18} className="mr-2 text-purple-500" />
                        Draft Introduction
                      </h4>
                      <p className="text-xs text-slate-500 mt-1">First touchpoint for new leads.</p>
                    </button>

                    <button 
                      onClick={() => handleGenerateEmail('followup')}
                      disabled={isGenerating}
                      className="p-4 bg-white border border-slate-200 rounded-lg hover:border-purple-300 hover:bg-purple-50 transition text-left group"
                    >
                      <h4 className="font-semibold text-slate-700 group-hover:text-purple-700 flex items-center">
                        <Calendar size={18} className="mr-2 text-purple-500" />
                        Draft Follow-up
                      </h4>
                      <p className="text-xs text-slate-500 mt-1">Check in after sending an estimate.</p>
                    </button>

                    <button 
                      onClick={() => handleGenerateEmail('estimate')}
                      disabled={isGenerating}
                      className="p-4 bg-white border border-slate-200 rounded-lg hover:border-purple-300 hover:bg-purple-50 transition text-left group"
                    >
                      <h4 className="font-semibold text-slate-700 group-hover:text-purple-700 flex items-center">
                        <FileText size={18} className="mr-2 text-purple-500" />
                        Estimate Cover Email
                      </h4>
                      <p className="text-xs text-slate-500 mt-1">Professional email to attach to quote.</p>
                    </button>

                    <button 
                      onClick={handleSummarize}
                      disabled={isGenerating}
                      className="p-4 bg-white border border-slate-200 rounded-lg hover:border-purple-300 hover:bg-purple-50 transition text-left group"
                    >
                      <h4 className="font-semibold text-slate-700 group-hover:text-purple-700 flex items-center">
                        <Brain size={18} className="mr-2 text-purple-500" />
                        Summarize Lead
                      </h4>
                      <p className="text-xs text-slate-500 mt-1">Analyze notes and suggest actions.</p>
