                  {isGenerating && (
                    <div className="flex items-center justify-center p-8 text-purple-600">
                      <Loader2 size={32} className="animate-spin mr-3" />
                      <span>{aiActionType}</span>
                    </div>
                  )}

                  {aiResponse && !isGenerating && (
                    <div className="bg-white rounded-lg border border-purple-200 shadow-sm overflow-hidden animate-in slide-in-from-bottom-5">
