  id: string;
  content: string;
  date: string;
  author: string;
}

export interface Lead {
  id: string;
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  address: string;
  status: LeadStatus;
  estimatedValue: number;
  roofType: string;
  notes: Note[];
  createdAt: string;
  lastContact: string;
}

export interface CallLog {
  id: string;
  leadId: string;
  leadName: string;
  date: string;
  duration: string;
  type: 'Inbound' | 'Outbound';
  status: 'Completed' | 'Missed' | 'Voicemail';
  summary: string;
}

