            <PhoneOutgoing size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500">Outbound</p>
            <p className="text-2xl font-bold text-slate-800">{outboundCalls}</p>
          </div>
        </div>
      </div>

      {/* Calls List */}
