import React from 'react';
import { CallLog } from '../types';
import { Phone, PhoneIncoming, Clock, CheckCircle2, XCircle, Voicemail } from 'lucide-react';

interface CallsPageProps {
  calls: CallLog[];
}

export const CallsPage: React.FC<CallsPageProps> = ({ calls }) => {
  // Filter for Inbound calls only
  const inboundCalls = calls.filter(c => c.type === 'Inbound');

  const totalInbound = inboundCalls.length;
  const completedCalls = inboundCalls.filter(c => c.status === 'Completed').length;
  const missedCalls = inboundCalls.filter(c => c.status === 'Missed' || c.status === 'Voicemail').length;

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'Completed': return <CheckCircle2 size={16} className="text-green-500" />;
      case 'Missed': return <XCircle size={16} className="text-red-500" />;
      case 'Voicemail': return <Voicemail size={16} className="text-orange-500" />;
      default: return <Clock size={16} className="text-slate-400" />;
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <h1 className="text-3xl font-bold text-slate-800">Inbound Call Logs</h1>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-blue-100 rounded-full text-blue-600">
            <PhoneIncoming size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500">Total Inbound</p>
            <p className="text-2xl font-bold text-slate-800">{totalInbound}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-green-100 rounded-full text-green-600">
            <CheckCircle2 size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500">Answered</p>
            <p className="text-2xl font-bold text-slate-800">{completedCalls}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-red-100 rounded-full text-red-600">
            <XCircle size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500">Missed / Voicemail</p>
            <p className="text-2xl font-bold text-slate-800">{missedCalls}</p>
          </div>
        </div>
      </div>

      {/* Calls List */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50">
          <h2 className="font-semibold text-slate-700">Recent Inbound Activity</h2>
        </div>
        <div className="divide-y divide-slate-100">
          {inboundCalls.length === 0 ? (
            <div className="p-8 text-center text-slate-400">
              No inbound calls recorded.
            </div>
          ) : (
            inboundCalls.map((call) => (
              <div key={call.id} className="p-4 hover:bg-slate-50 transition duration-150">
                <div className="flex flex-col md:flex-row justify-between md:items-start gap-4">
                  {/* Left Side: Icon & Basic Info */}
                  <div className="flex items-start space-x-4">
                    <div className="p-2 rounded-full mt-1 bg-blue-50 text-blue-600">
                      <PhoneIncoming size={20} />
                    </div>
                    <div>
                      <h3 className="font-medium text-slate-800">{call.leadName}</h3>
                      <div className="flex items-center text-xs text-slate-500 mt-1 space-x-2">
                        <span className="flex items-center">
                          <Clock size={12} className="mr-1" />
                          {call.date}
                        </span>
                        <span>•</span>
                        <span>{call.duration}</span>
                        <span>•</span>
                        <span className="flex items-center gap-1">
                          {getStatusIcon(call.status)}
                          {call.status}
                        </span>
                      </div>
                    </div>
                  </div>

                  {/* Right Side: Summary */}
                  <div className="flex-1 md:max-w-2xl bg-slate-50 p-3 rounded-lg border border-slate-100">
                    <p className="text-sm text-slate-600 leading-relaxed">
                      <span className="font-semibold text-slate-700 block text-xs uppercase tracking-wide mb-1">Summary</span>
                      {call.summary}
                    </p>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

