                  onClick={handleSync}
                  disabled={isLoading}
                  className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-sm font-medium flex items-center transition disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {isLoading ? (
                    <span className="flex items-center">Syncing...</span>
                  ) : (
                    <>
                      <DownloadCloud size={16} className="mr-2" />
                      Sync Data
                    </>
                  )}
                </button>
              </div>
            </div>

            {status === 'success' && (
              <div className="flex items-center text-green-600 text-sm bg-green-50 p-3 rounded-lg border border-green-100">
                <CheckCircle2 size={16} className="mr-2" />
