              <span className="bg-slate-100 px-2 py-1 rounded">Type (Inbound)</span>
              <span className="bg-slate-100 px-2 py-1 rounded">Status</span>
              <span className="bg-slate-100 px-2 py-1 rounded">Summary</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

