import { CallLog } from "../types";

const normalizeToCsvUrl = (url: string): string => {
  // If it's already a CSV export link or raw file, return it
  if (url.includes('output=csv') || url.includes('export?format=csv')) return url;

  // Extract Sheet ID from standard URL (e.g. .../d/SHEET_ID/edit...)
  const match = url.match(/\/d\/([a-zA-Z0-9-_]+)/);
  if (match && match[1]) {
    const sheetId = match[1];
    // Convert to export URL
    return `https://docs.google.com/spreadsheets/d/${sheetId}/export?format=csv`;
  }

  return url;
};

export const fetchGoogleSheetData = async (url: string): Promise<any[]> => {
  try {
    const csvUrl = normalizeToCsvUrl(url);
    console.log("Fetching from:", csvUrl); // Debugging

    const response = await fetch(csvUrl);
    if (!response.ok) throw new Error('Failed to fetch CSV');
    const text = await response.text();
    return parseCSV(text);
  } catch (error) {
    console.error("Error fetching Google Sheet:", error);
    throw error;
  }
};

const parseCSV = (text: string) => {
  const lines = text.split('\n').filter(l => l.trim());
  if (lines.length < 2) return [];

  // Parse headers (simple split, assuming standard CSV header line)
  const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, '').toLowerCase());

  return lines.slice(1).map((line, idx) => {
    // Robust CSV line parser handling quotes
    const values: string[] = [];
    let inQuote = false;
    let currentVal = '';

    for (let i = 0; i < line.length; i++) {
      const char = line[i];
      if (char === '"') {
        inQuote = !inQuote;
      } else if (char === ',' && !inQuote) {
        values.push(currentVal.trim().replace(/^"|"$/g, '').replace(/""/g, '"'));
        currentVal = '';
      } else {
        currentVal += char;
      }
    }
    values.push(currentVal.trim().replace(/^"|"$/g, '').replace(/""/g, '"'));

    const obj: any = { id: `imported-${idx}` };
    headers.forEach((h, i) => {
      if (values[i] !== undefined) obj[h] = values[i];
    });
    return obj;
  });
};

export const mapToCallLogs = (data: any[]): CallLog[] => {
  return data.map((row, index) => {
    // Flexible column matching
    const leadName = row['lead name'] || row['name'] || row['customer'] || 'Unknown';
    const rawType = row['type'] || 'Inbound';
    const type = rawType.toLowerCase().includes('out') ? 'Outbound' : 'Inbound';

    let status: any = 'Completed';
    const rowStatus = (row['status'] || '').toLowerCase();
    if (rowStatus.includes('redirect')) status = 'Redirected';
    else if (rowStatus.includes('voice')) status = 'Voicemail';
    else if (rowStatus.includes('missed')) status = 'Voicemail'; 

    return {
      id: row.id || `call-${index}`,
      leadId: row['lead id'] || `gen-${index}`,
      leadName: leadName,
      date: row['date'] || new Date().toLocaleDateString(),
      duration: row['duration'] || '0m 0s',
      type: type as 'Inbound' | 'Outbound',
      status: status as 'Completed' | 'Redirected' | 'Voicemail',
      summary: row['summary'] || row['notes'] || row['description'] || 'No summary provided.'
    };
  });
};

