import { CallLog, Lead, LeadStatus } from "../types";

const normalizeToCsvUrl = (url: string): string => {
  if (url.includes('output=csv') || url.includes('export?format=csv')) return url;
  const match = url.match(/\/d\/([a-zA-Z0-9-_]+)/);
  if (match && match[1]) {
    const sheetId = match[1];
    return `https://docs.google.com/spreadsheets/d/${sheetId}/export?format=csv`;
  }
  return url;
};

export const fetchGoogleSheetData = async (url: string): Promise<any[]> => {
  try {
    const csvUrl = normalizeToCsvUrl(url);
    const response = await fetch(csvUrl);
    if (!response.ok) throw new Error('Failed to fetch CSV');
    const text = await response.text();
    return parseCSV(text);
  } catch (error) {
    console.error("Error fetching Google Sheet:", error);
    throw error;
  }
};

const parseCSV = (text: string) => {
  const lines = text.split('\n').filter(l => l.trim());
  if (lines.length < 2) return [];

  const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, '').toLowerCase());

  return lines.slice(1).map((line, idx) => {
    const values: string[] = [];
    let inQuote = false;
    let currentVal = '';

    for (let i = 0; i < line.length; i++) {
      const char = line[i];
      if (char === '"') {
        inQuote = !inQuote;
      } else if (char === ',' && !inQuote) {
        values.push(currentVal.trim().replace(/^"|"$/g, '').replace(/""/g, '"'));
        currentVal = '';
      } else {
        currentVal += char;
      }
    }
    values.push(currentVal.trim().replace(/^"|"$/g, '').replace(/""/g, '"'));

    const obj: any = { id: `imported-${idx}` };
    headers.forEach((h, i) => {
      if (values[i] !== undefined) obj[h] = values[i];
    });
    return obj;
  });
};

export const mapToCallLogs = (data: any[]): CallLog[] => {
  return data.map((row, index) => {
    const leadName = row['lead name'] || row['name'] || row['customer'] || 'Unknown';
    const rawType = row['type'] || 'Inbound';
    const type = rawType.toLowerCase().includes('out') ? 'Outbound' : 'Inbound';

    let status: any = 'Completed';
    const rowStatus = (row['status'] || '').toLowerCase();
    if (rowStatus.includes('redirect')) status = 'Redirected';
    else if (rowStatus.includes('voice')) status = 'Voicemail';
    else if (rowStatus.includes('missed')) status = 'Voicemail'; 

    return {
      id: row.id || `call-${index}`,
      leadId: `lead-${leadName.replace(/\s/g, '-').toLowerCase()}`,
      leadName: leadName,
      date: row['date'] || new Date().toLocaleDateString(),
      duration: row['duration'] || '0m 0s',
      type: type as 'Inbound' | 'Outbound',
      status: status as 'Completed' | 'Redirected' | 'Voicemail',
      summary: row['summary'] || row['notes'] || row['description'] || 'No summary provided.'
    };
  });
};

export const mapToLeads = (data: any[]): Lead[] => {
  const leadsMap = new Map<string, Lead>();

  data.forEach((row, index) => {
    const name = row['lead name'] || row['name'] || row['customer'] || 'Unknown Lead';
    if (name === 'Unknown Lead' || !name) return;

    // Try to parse financial value
    const rawValue = row['value'] || row['amount'] || row['estimate'] || row['price'] || '0';
    // Remove currency symbols and commas, parse float
    const value = parseFloat(rawValue.replace(/[^0-9.-]+/g,"")) || 0;

    // Try to parse lead status (look for a specific 'stage' or 'lead status' column, 
    // or fallback to 'status' if it doesn't look like a call status)
    // If the sheet is just a call log, we might not find good status data, so we default to 'New' or 'Contacted'
    const rawStatus = (row['lead status'] || row['stage'] || row['status'] || '').toLowerCase();

    let status: LeadStatus = 'New';

    // Heuristics to determine Lead Status from potentially messy sheet data
    if (rawStatus.includes('sold') || rawStatus.includes('completed') || rawStatus.includes('won')) status = 'Completed';
    else if (rawStatus.includes('progress') || rawStatus.includes('started')) status = 'In Progress';
    else if (rawStatus.includes('schedule')) status = 'Scheduled';
    else if (rawStatus.includes('estimate') || rawStatus.includes('quote') || rawStatus.includes('sent')) status = 'Estimate Sent';
    else if (rawStatus.includes('lost') || rawStatus.includes('dead') || rawStatus.includes('archived')) status = 'Lost';
    else if (rawStatus.includes('contact') || rawStatus.includes('call') || rawStatus.includes('voice')) status = 'Contacted';

    // If we've seen this lead before, update it with more recent/complete info
    if (leadsMap.has(name)) {
      const existing = leadsMap.get(name)!;

      // Accumulate value if multiple rows have values (e.g. multiple jobs) or take the max
      if (value > existing.estimatedValue) existing.estimatedValue = value;

      // Update status if the new row seems to indicate progress (simplified logic)
      if (status !== 'New' && status !== 'Contacted') existing.status = status;

      // Update details if missing
      if (!existing.email && row['email']) existing.email = row['email'];
      if (!existing.phone && row['phone']) existing.phone = row['phone'];
      if (!existing.address && row['address']) existing.address = row['address'];

      // Update last contact date
      const rowDate = new Date(row['date']);
      const existingDate = new Date(existing.lastContact);
      if (!isNaN(rowDate.getTime()) && rowDate > existingDate) {
        existing.lastContact = row['date'];
      }

    } else {
      // Create new lead
      leadsMap.set(name, {
        id: `lead-${name.replace(/\s/g, '-').toLowerCase()}`,
        firstName: name.split(' ')[0] || name,
        lastName: name.split(' ').slice(1).join(' ') || '',
        email: row['email'] || '',
        phone: row['phone'] || '',
        address: row['address'] || '',
        status: status,
        estimatedValue: value,
        roofType: row['roof type'] || 'Unspecified',
        notes: [], 
        createdAt: row['date'] || new Date().toLocaleDateString(),
        lastContact: row['date'] || new Date().toLocaleDateString()
      });
    }
  });

  return Array.from(leadsMap.values());
};

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { DollarSign, HardHat, FileText, TrendingUp, AlertCircle } from 'lucide-react';
import { Lead } from '../types';

interface DashboardProps {
  leads: Lead[];
}

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#6366f1'];

export const Dashboard: React.FC<DashboardProps> = ({ leads }) => {

  // 1. Calculate Pipeline Value
  // We only count value if status is not Lost or Completed (Active Pipeline)
  const totalPipelineValue = leads.reduce((acc, lead) => {
    return acc + (lead.status !== 'Lost' && lead.status !== 'Completed' ? lead.estimatedValue : 0);
  }, 0);

  // 2. Calculate Counts
  const activeJobs = leads.filter(l => l.status === 'In Progress' || l.status === 'Scheduled').length;
  const pendingEstimates = leads.filter(l => l.status === 'Estimate Sent').length;
  const completedJobs = leads.filter(l => l.status === 'Completed').length;

  // 3. Status Distribution for Pie Chart
  // Filter out statuses with 0 count to clean up chart
  const statusCounts: Record<string, number> = {};
  leads.forEach(l => {
    statusCounts[l.status] = (statusCounts[l.status] || 0) + 1;
  });

  const statusData = Object.keys(statusCounts).map(status => ({
    name: status,
    value: statusCounts[status]
  }));

  // 4. Revenue Trend (Mock logic based on "Completed" leads with dates)
  // We try to group completed jobs by month based on `lastContact` or `createdAt`
  const revenueByMonth: Record<string, number> = {};
  let hasRevenueData = false;

  leads.forEach(l => {
    if (l.status === 'Completed' && l.estimatedValue > 0) {
      const date = new Date(l.lastContact);
      if (!isNaN(date.getTime())) {
        const month = date.toLocaleString('default', { month: 'short' });
        revenueByMonth[month] = (revenueByMonth[month] || 0) + l.estimatedValue;
        hasRevenueData = true;
      }
    }
  });

  // Sort months logic (simplified) or just use keys
  const revenueData = Object.keys(revenueByMonth).map(month => ({
    name: month,
    revenue: revenueByMonth[month]
  }));

  // --- Checks for "Not Enough Data" ---
  const hasValueData = leads.some(l => l.estimatedValue > 0);
  const hasStatusData = leads.some(l => l.status !== 'New' && l.status !== 'Contacted'); // If everyone is just "New", we probably lack status data

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold text-slate-800">Executive Dashboard</h1>
        <span className="text-xs text-slate-500 bg-slate-100 px-2 py-1 rounded-full">
          Data Source: Google Sheets
        </span>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {/* Pipeline Value */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-blue-100 rounded-full text-blue-600">
            <DollarSign size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500">Pipeline Value</p>
            {hasValueData ? (
              <p className="text-2xl font-bold text-slate-800">${totalPipelineValue.toLocaleString()}</p>
            ) : (
              <p className="text-sm font-medium text-slate-400 italic mt-1">Not enough data</p>
            )}
          </div>
        </div>

        {/* Active Jobs */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-orange-100 rounded-full text-orange-600">
            <HardHat size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500">Active Jobs</p>
            {hasStatusData ? (
              <p className="text-2xl font-bold text-slate-800">{activeJobs}</p>
            ) : (
              <p className="text-sm font-medium text-slate-400 italic mt-1">Not enough data</p>
            )}
          </div>
        </div>

        {/* Pending Estimates */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-purple-100 rounded-full text-purple-600">
            <FileText size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500">Pending Estimates</p>
            {hasStatusData ? (
              <p className="text-2xl font-bold text-slate-800">{pendingEstimates}</p>
            ) : (
               <p className="text-sm font-medium text-slate-400 italic mt-1">Not enough data</p>
            )}
          </div>
        </div>

        {/* Completed Jobs */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-green-100 rounded-full text-green-600">
            <TrendingUp size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500">Completed Jobs</p>
            {hasStatusData ? (
              <p className="text-2xl font-bold text-slate-800">{completedJobs}</p>
            ) : (
              <p className="text-sm font-medium text-slate-400 italic mt-1">Not enough data</p>
            )}
          </div>
        </div>
      </div>

      {/* Info Banner if data missing */}
      {(!hasValueData || !hasStatusData) && (
        <div className="bg-blue-50 border border-blue-100 text-blue-800 p-4 rounded-lg flex items-start text-sm">
          <AlertCircle size={18} className="mr-2 mt-0.5 flex-shrink-0" />
          <div>
            <p className="font-semibold">Missing Analytics Data</p>
            <p>
              To populate these charts, add the following columns to your Google Sheet: 
              <span className="font-mono bg-blue-100 px-1 rounded mx-1">Value</span> 
              (for revenue/pipeline) and 
              <span className="font-mono bg-blue-100 px-1 rounded mx-1">Stage</span> 
              or 
              <span className="font-mono bg-blue-100 px-1 rounded mx-1">Status</span> 
              (e.g., "Sold", "Estimate Sent", "In Progress").
            </p>
          </div>
        </div>
      )}

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Status Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex flex-col">
          <h3 className="text-lg font-semibold mb-4 text-slate-700">Lead Status Distribution</h3>
          <div className="flex-1 min-h-[250px] relative">
            {leads.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={statusData}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                  >
                    {statusData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="absolute inset-0 flex items-center justify-center text-slate-400">
                No leads data available
              </div>
            )}
          </div>
          <div className="flex flex-wrap justify-center gap-4 text-sm text-slate-600 mt-4">
            {statusData.map((entry, index) => (
              <div key={entry.name} className="flex items-center">
                <div className="w-3 h-3 rounded-full mr-2" style={{ backgroundColor: COLORS[index % COLORS.length] }}></div>
                {entry.name} ({entry.value})
              </div>
            ))}
          </div>
        </div>

        {/* Revenue Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex flex-col">
          <h3 className="text-lg font-semibold mb-4 text-slate-700">Revenue Trend (Completed Jobs)</h3>
          <div className="flex-1 min-h-[250px] relative">
            {hasRevenueData ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={revenueData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} />
                  <YAxis axisLine={false} tickLine={false} tickFormatter={(val) => `$${val/1000}k`} />
                  <Tooltip formatter={(val: number) => `$${val.toLocaleString()}`} cursor={{fill: 'transparent'}} />
                  <Bar dataKey="revenue" fill="#3b82f6" radius={[4, 4, 0, 0]} barSize={40} />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-400 bg-slate-50/50 rounded-lg">
                <TrendingUp size={32} className="mb-2 opacity-20" />
                <p>Not enough data for Revenue Trend.</p>
                <p className="text-xs mt-1 opacity-70">Mark jobs as 'Completed' with a 'Value' to see this chart.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { LayoutDashboard, Users, Settings, Bell, Search, Hammer, LogOut, Menu, Phone } from 'lucide-react';
import { Dashboard } from './components/Dashboard';
import { LeadsBoard } from './components/LeadsBoard';
import { LeadDetail } from './components/LeadDetail';
import { CallsPage } from './components/CallsPage';
import { SettingsPage } from './components/SettingsPage';
import { Lead, CallLog } from './types';
import { fetchGoogleSheetData, mapToCallLogs, mapToLeads } from './services/googleSheetService';

// The specific Google Sheet provided by the user
export const DEFAULT_SHEET_URL = 'https://docs.google.com/spreadsheets/d/1L436XpTdCvW7ryv9P2AVy1h8mUsgMz_Hxrmxnl1OyQA/edit?usp=sharing';

function App() {
  const [currentView, setCurrentView] = useState<'dashboard' | 'leads' | 'calls' | 'settings'>('dashboard');

  // Initialize with empty array, data will load from Sheet
  const [leads, setLeads] = useState<Lead[]>([]);
  const [calls, setCalls] = useState<CallLog[]>([]);

  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);
  const [isSidebarOpen, setSidebarOpen] = useState(false);
  const [isLoadingData, setIsLoadingData] = useState(false);

  // Auto-load data from the default Google Sheet on mount
  useEffect(() => {
    const loadData = async () => {
      // Check for user override, otherwise use default
      const savedSheetUrl = localStorage.getItem('crm_sheet_url') || DEFAULT_SHEET_URL;

      console.log('Syncing data from:', savedSheetUrl);
      setIsLoadingData(true);
      try {
        const data = await fetchGoogleSheetData(savedSheetUrl);
        if (data && data.length > 0) {
          // Parse Calls
          const parsedCalls = mapToCallLogs(data);
          setCalls(parsedCalls);

          // Parse Leads (aggregating from rows)
          const parsedLeads = mapToLeads(data);
          setLeads(parsedLeads);

          console.log(`Loaded ${parsedCalls.length} calls and ${parsedLeads.length} leads.`);
        } else {
          console.warn("No data found in sheet");
        }
      } catch (err) {
        console.error("Failed to auto-sync data:", err);
      } finally {
        setIsLoadingData(false);
      }
    };

    loadData();
  }, []); 

  const handleUpdateLead = (updatedLead: Lead) => {
    setLeads(leads.map(l => l.id === updatedLead.id ? updatedLead : l));
    setSelectedLead(updatedLead);
  };

  const handleSyncCalls = (newCalls: CallLog[]) => {
    // This mostly happens from Settings manual sync
    // We should ideally reload leads here too, but for now we just update calls
    setCalls(newCalls);
    setCurrentView('calls');
  };

  const handleAddLeadPlaceholder = () => {
    const newLead: Lead = {
      id: Date.now().toString(),
      firstName: 'New',
      lastName: 'Customer',
      email: '',
      phone: '',
      address: 'Enter address...',
      status: 'New',
      estimatedValue: 0,
      roofType: 'Unspecified',
      notes: [],
      createdAt: new Date().toLocaleDateString(),
      lastContact: new Date().toLocaleDateString()
    };
    setLeads([newLead, ...leads]);
    setSelectedLead(newLead);
  };

  return (
    <div className="flex h-screen bg-slate-50 font-sans text-slate-900 overflow-hidden">

      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-20 md:hidden"
          onClick={() => setSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`fixed md:relative z-30 w-64 h-full bg-slate-900 text-slate-300 flex flex-col transition-transform duration-300 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <div className="p-6 flex items-center space-x-3 border-b border-slate-800">
          <div className="bg-blue-600 p-2 rounded-lg">
            <Hammer className="text-white" size={24} />
          </div>
          <span className="text-xl font-bold text-white tracking-tight">Summit CRM</span>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2">
          <button 
            onClick={() => { setCurrentView('dashboard'); setSidebarOpen(false); }}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition duration-200 ${currentView === 'dashboard' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/50' : 'hover:bg-slate-800 hover:text-white'}`}
          >
            <div className="flex items-center w-full justify-between">
              <div className="flex items-center space-x-3">
                <LayoutDashboard size={20} />
                <span className="font-medium">Dashboard</span>
              </div>
              {isLoadingData && <span className="w-2 h-2 bg-blue-400 rounded-full animate-pulse"></span>}
            </div>
          </button>

          <button 
            onClick={() => { setCurrentView('leads'); setSidebarOpen(false); }}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition duration-200 ${currentView === 'leads' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/50' : 'hover:bg-slate-800 hover:text-white'}`}
          >
            <Users size={20} />
            <span className="font-medium">Leads</span>
          </button>

          <button 
            onClick={() => { setCurrentView('calls'); setSidebarOpen(false); }}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition duration-200 ${currentView === 'calls' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/50' : 'hover:bg-slate-800 hover:text-white'}`}
          >
             <Phone size={20} />
             <span className="font-medium">Calls</span>
          </button>

          <button 
            onClick={() => { setCurrentView('settings'); setSidebarOpen(false); }}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition duration-200 ${currentView === 'settings' ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/50' : 'hover:bg-slate-800 hover:text-white'}`}
          >
            <Settings size={20} />
            <span className="font-medium">Settings</span>
          </button>
        </nav>

        <div className="p-4 border-t border-slate-800">
          <button className="w-full flex items-center space-x-3 px-4 py-3 rounded-lg hover:bg-red-900/20 hover:text-red-400 transition text-slate-400">
            <LogOut size={20} />
            <span className="font-medium">Sign Out</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative">
        {/* Top Header */}
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shadow-sm z-10">
          <div className="flex items-center">
            <button 
              onClick={() => setSidebarOpen(true)}
              className="mr-4 p-2 rounded-lg hover:bg-slate-100 md:hidden"
            >
              <Menu size={24} className="text-slate-600" />
            </button>
            <h2 className="text-lg font-semibold text-slate-700 hidden sm:block">
              {currentView === 'dashboard' ? 'Overview' : 
               currentView === 'leads' ? 'Pipeline' : 
               currentView === 'calls' ? 'Call Activity' : 'Settings'}
            </h2>
          </div>

          <div className="flex items-center space-x-4">
             <div className="relative hidden md:block">
               <input 
                  type="text" 
                  placeholder="Global search..." 
                  className="pl-9 pr-4 py-2 bg-slate-100 border-transparent focus:bg-white focus:ring-2 focus:ring-blue-500 rounded-full text-sm w-64 transition-all"
               />
               <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
             </div>
             <button className="p-2 relative rounded-full hover:bg-slate-100 text-slate-500 transition">
               <Bell size={20} />
               <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border border-white"></span>
             </button>
             <div className="w-8 h-8 rounded-full bg-blue-100 border border-blue-200 flex items-center justify-center text-blue-700 font-bold text-sm">
               JD
             </div>
          </div>
        </header>

        {/* View Content */}
        <div className="flex-1 overflow-auto p-4 md:p-8">
          {currentView === 'dashboard' && <Dashboard leads={leads} />}
          {currentView === 'leads' && (
            <LeadsBoard 
              leads={leads} 
              onSelectLead={setSelectedLead} 
              onAddLead={handleAddLeadPlaceholder}
            />
          )}
          {currentView === 'calls' && <CallsPage calls={calls} />}
          {currentView === 'settings' && <SettingsPage onSyncCalls={handleSyncCalls} />}
        </div>
      </main>

      {/* Modal Overlay for Lead Detail */}
      {selectedLead && (
        <LeadDetail 
          lead={selectedLead} 
          onClose={() => setSelectedLead(null)} 
          onUpdateLead={handleUpdateLead}
        />
      )}
    </div>
  );
}

export default App;

