import { CallLog, Lead, LeadStatus } from "../types";

const normalizeToCsvUrl = (url: string): string => {
  if (url.includes('output=csv') || url.includes('export?format=csv')) return url;
  const match = url.match(/\/d\/([a-zA-Z0-9-_]+)/);
  if (match && match[1]) {
    const sheetId = match[1];
    // Preserve gid if present in the original URL to allow fetching specific tabs
    const gidMatch = url.match(/gid=([0-9]+)/);
    const gidParam = gidMatch ? `&gid=${gidMatch[1]}` : '';
    return `https://docs.google.com/spreadsheets/d/${sheetId}/export?format=csv${gidParam}`;
  }
  return url;
};

export const fetchGoogleSheetData = async (url: string): Promise<any[]> => {
  try {
    const csvUrl = normalizeToCsvUrl(url);
    const response = await fetch(csvUrl);
    if (!response.ok) throw new Error('Failed to fetch CSV');
    const text = await response.text();
    return parseCSV(text);
  } catch (error) {
    console.error("Error fetching Google Sheet:", error);
    throw error;
  }
};

const parseCSV = (text: string) => {
  const rows: any[] = [];
  let headers: string[] = [];

  let currentRow: string[] = [];
  let currentVal = '';
  let inQuote = false;

  // Robust parsing loop to handle newlines inside quotes
  for (let i = 0; i < text.length; i++) {
    const char = text[i];
    const nextChar = text[i + 1];

    if (char === '"') {
      if (inQuote && nextChar === '"') {
        currentVal += '"';
        i++; // skip escaped quote
      } else {
        inQuote = !inQuote;
      }
    } else if (char === ',' && !inQuote) {
      currentRow.push(currentVal.trim());
      currentVal = '';
    } else if ((char === '\r' || char === '\n') && !inQuote) {
      if (char === '\r' && nextChar === '\n') i++; // Handle CRLF

      currentRow.push(currentVal.trim());

      // Process the completed row
      if (headers.length === 0) {
        // First row is headers
        headers = currentRow.map(h => h.toLowerCase().replace(/^"|"$/g, ''));
      } else {
         // Data row
         const obj: any = { id: `row-${rows.length}` };
         headers.forEach((h, idx) => {
           if (currentRow[idx] !== undefined) {
             // Clean up quotes around values if they exist after parsing
             obj[h] = currentRow[idx].replace(/^"|"$/g, ''); 
           }
         });
         // Only add if it's not a completely empty row
         if (Object.keys(obj).length > 1) {
            rows.push(obj);
         }
      }

      currentRow = [];
      currentVal = '';
    } else {
      currentVal += char;
    }
  }

  // Handle last row if no newline at end of file
  if (currentRow.length > 0 || currentVal.length > 0) {
    currentRow.push(currentVal.trim());
    if (headers.length === 0) {
        headers = currentRow.map(h => h.toLowerCase().replace(/^"|"$/g, ''));
    } else {
         const obj: any = { id: `row-${rows.length}` };
         headers.forEach((h, idx) => {
           if (currentRow[idx] !== undefined) obj[h] = currentRow[idx].replace(/^"|"$/g, '');
         });
         rows.push(obj);
    }
  }

  return rows;
};

export const mapToCallLogs = (data: any[]): CallLog[] => {
  return data.map((row, index) => {
    // 1. Identify the Lead Name
    const leadName = row['lead name'] || row['name'] || row['customer'] || row['client'] || 'Unknown';

    // 2. Identify Type (Inbound/Outbound)
    const rawType = row['type'] || row['direction'] || 'Inbound';
    const type = rawType.toLowerCase().includes('out') ? 'Outbound' : 'Inbound';

    // 3. Identify Status
    let status: any = 'Completed';
    const rowStatus = (row['status'] || row['call status'] || row['outcome'] || '').toLowerCase();

    if (rowStatus.includes('redirect')) status = 'Redirected';
    else if (rowStatus.includes('voice') || rowStatus.includes('missed') || rowStatus.includes('no answer')) status = 'Voicemail'; 
    else if (rowStatus.includes('answered') || rowStatus.includes('completed')) status = 'Completed';

    // 4. Identify Summary - Aggressively check common column names
    const summary = 
      row['summary'] || 
      row['call summary'] || 
      row['notes'] || 
      row['call notes'] || 
      row['description'] || 
      row['transcript'] || 
      row['transcription'] || 
      row['message'] || 
      row['details'] || 
      row['content'] || 
      'No summary provided.';

    // 5. Date Parsing
    const rawDate = row['date'] || row['time'] || row['created at'] || new Date().toLocaleDateString();

    // 6. Duration
    const duration = row['duration'] || row['length'] || '0m 0s';

    return {
      id: row.id || `call-${index}`,
      leadId: `lead-${leadName.replace(/\s/g, '-').toLowerCase()}`,
      leadName: leadName,
      date: rawDate,
      duration: duration,
      type: type as 'Inbound' | 'Outbound',
      status: status as 'Completed' | 'Redirected' | 'Voicemail',
      summary: summary
    };
  });
};

export const mapToLeads = (data: any[]): Lead[] => {
  const leadsMap = new Map<string, Lead>();

  data.forEach((row, index) => {
    const name = row['lead name'] || row['name'] || row['customer'] || row['client'] || 'Unknown Lead';
    if (name === 'Unknown Lead' || !name) return;

    // Try to parse financial value
    const rawValue = row['value'] || row['amount'] || row['estimate'] || row['price'] || row['revenue'] || '0';
    const value = parseFloat(rawValue.replace(/[^0-9.-]+/g,"")) || 0;

    const rawStatus = (row['lead status'] || row['stage'] || row['status'] || '').toLowerCase();

    let status: LeadStatus = 'New';

    if (rawStatus.includes('sold') || rawStatus.includes('completed') || rawStatus.includes('won')) status = 'Completed';
    else if (rawStatus.includes('progress') || rawStatus.includes('started')) status = 'In Progress';
    else if (rawStatus.includes('schedule')) status = 'Scheduled';
    else if (rawStatus.includes('estimate') || rawStatus.includes('quote') || rawStatus.includes('sent')) status = 'Estimate Sent';
    else if (rawStatus.includes('lost') || rawStatus.includes('dead') || rawStatus.includes('archived')) status = 'Lost';
    else if (rawStatus.includes('contact') || rawStatus.includes('call') || rawStatus.includes('voice')) status = 'Contacted';

    // Only process if we haven't seen this lead or if we need to update stats
    if (leadsMap.has(name)) {
      const existing = leadsMap.get(name)!;
      if (value > existing.estimatedValue) existing.estimatedValue = value;
      if (status !== 'New' && status !== 'Contacted') existing.status = status;

      if (!existing.email && row['email']) existing.email = row['email'];
      if (!existing.phone && row['phone']) existing.phone = row['phone'];
      if (!existing.address && row['address']) existing.address = row['address'];

      // Note: If this row has a summary/note, we could technically add it to lead notes, 
      // but for now we focus on the Calls view for summaries.
    } else {
      leadsMap.set(name, {
        id: `lead-${name.replace(/\s/g, '-').toLowerCase()}`,
        firstName: name.split(' ')[0] || name,
        lastName: name.split(' ').slice(1).join(' ') || '',
        email: row['email'] || '',
        phone: row['phone'] || '',
        address: row['address'] || '',
        status: status,
        estimatedValue: value,
        roofType: row['roof type'] || 'Unspecified',
        notes: [], 
        createdAt: row['date'] || new Date().toLocaleDateString(),
        lastContact: row['date'] || new Date().toLocaleDateString()
      });
    }
  });

  return Array.from(leadsMap.values());
};

import React, { useState } from 'react';
import { Save, Database, AlertCircle, CheckCircle2, DownloadCloud } from 'lucide-react';
import { fetchGoogleSheetData, mapToCallLogs } from '../services/googleSheetService';
import { CallLog } from '../types';
import { DEFAULT_SHEET_URL } from '../App';

interface SettingsPageProps {
  onSyncCalls: (calls: CallLog[]) => void;
}

export const SettingsPage: React.FC<SettingsPageProps> = ({ onSyncCalls }) => {
  // Use saved URL or the application default
  const [sheetUrl, setSheetUrl] = useState(localStorage.getItem('crm_sheet_url') || DEFAULT_SHEET_URL);
  const [isLoading, setIsLoading] = useState(false);
  const [status, setStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [message, setMessage] = useState('');

  const handleSync = async () => {
    if (!sheetUrl) {
      setStatus('error');
      setMessage('Please enter a valid URL.');
      return;
    }

    setIsLoading(true);
    setStatus('idle');
    setMessage('');

    try {
      const rawData = await fetchGoogleSheetData(sheetUrl);
      if (rawData.length === 0) {
        throw new Error('No data found in the sheet. Please check the CSV format.');
      }

      const newCalls = mapToCallLogs(rawData);
      onSyncCalls(newCalls);

      // PERSIST THE URL: Save to local storage on success
      localStorage.setItem('crm_sheet_url', sheetUrl);

      setStatus('success');
      setMessage(`Successfully synced ${newCalls.length} calls from Google Sheets.`);
    } catch (error) {
      console.error(error);
      setStatus('error');
      setMessage('Failed to sync. Please ensure the link is accessible and Public/Shared.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in duration-500">
      <div className="border-b border-slate-200 pb-4">
        <h1 className="text-3xl font-bold text-slate-800">Settings</h1>
        <p className="text-slate-500 mt-2">Manage data sources and application preferences.</p>
      </div>

      {/* Data Source Section */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-6 border-b border-slate-100 bg-slate-50 flex items-center space-x-3">
          <Database className="text-blue-600" size={20} />
          <h2 className="font-semibold text-slate-800">Google Sheets Integration</h2>
        </div>

        <div className="p-6 space-y-6">
          <div className="bg-blue-50 border border-blue-100 rounded-lg p-4 text-sm text-blue-800">
            <h3 className="font-semibold mb-2 flex items-center">
              <AlertCircle size={16} className="mr-2" />
              Connection Status
            </h3>
