import { GoogleGenAI } from "@google/genai";
import { Lead } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const MODEL_NAME = 'gemini-2.5-flash';

export const generateEmailDraft = async (lead: Lead, type: 'intro' | 'followup' | 'estimate' | 'closing'): Promise<string> => {
  if (!apiKey) return "API Key is missing. Please check your environment configuration.";

  let prompt = "";

  switch (type) {
    case 'intro':
      prompt = `Write a friendly, professional introduction email to a potential customer named ${lead.firstName} ${lead.lastName}. They inquired about a roof inspection for their property at ${lead.address}. Focus on trust and scheduling a free inspection.`;
      break;
    case 'followup':
      prompt = `Write a polite follow-up email to ${lead.firstName} checking in on the roof estimate we sent recently. Remind them of the value of a timely repair. The roof type is ${lead.roofType}.`;
      break;
    case 'estimate':
      prompt = `Write a cover email for a roofing estimate attachment (I will attach the PDF later, just write the body) for ${lead.firstName}. The estimated value is $${lead.estimatedValue.toLocaleString()}. Mention our quality materials and warranty.`;
      break;
    case 'closing':
      prompt = `Write a thank you email to ${lead.firstName} for choosing us for their roofing project. The job is marked as Completed. Ask for a review if they are satisfied.`;
      break;
  }

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: "You are a professional sales assistant for 'Kattoyksikkö IPM', a high-end roofing contractor. Your tone is professional, reliable, and warm. Keep emails concise and actionable.",
        temperature: 0.7,
      }
    });
    return response.text || "Could not generate email.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Error generating content. Please try again.";
  }
};

export const summarizeLead = async (lead: Lead): Promise<string> => {
  if (!apiKey) return "API Key is missing.";

  const notesText = lead.notes.map(n => `[${n.date}] ${n.author}: ${n.content}`).join("\n");

  const prompt = `Analyze the following notes for customer ${lead.firstName} ${lead.lastName} and provide a 2-sentence summary of the current relationship status and what the next best action is.\n\nNotes:\n${notesText}`;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
    });
    return response.text || "No summary available.";
  } catch (error) {
    console.error(error);
    return "Error generating summary.";
  }
};

