import React, { useState, useEffect } from 'react';
import { LayoutDashboard, Users, Settings, Bell, Search, Menu, Phone, AlertCircle } from 'lucide-react';
import { Dashboard } from './components/Dashboard';
import { LeadsBoard } from './components/LeadsBoard';
import { LeadDetail } from './components/LeadDetail';
import { CallsPage } from './components/CallsPage';
import { SettingsPage } from './components/SettingsPage';
import { Lead, CallLog } from './types';
import { fetchLeads, fetchCalls, updateLead, createLead } from './services/supabaseService';

function App() {
  const [currentView, setCurrentView] = useState<'dashboard' | 'leads' | 'calls' | 'settings'>('dashboard');

  const [leads, setLeads] = useState<Lead[]>([]);
  const [calls, setCalls] = useState<CallLog[]>([]);

  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);
  const [isSidebarOpen, setSidebarOpen] = useState(false);
  const [isLoadingData, setIsLoadingData] = useState(false);
  const [errorMsg, setErrorMsg] = useState('');

  // Auto-load data from Supabase on mount
  useEffect(() => {
    loadData();
  }, []); 

  const loadData = async () => {
    setIsLoadingData(true);
    setErrorMsg('');
    try {
      const [leadsData, callsData] = await Promise.all([
        fetchLeads(),
        fetchCalls()
      ]);
      setLeads(leadsData);
      setCalls(callsData);
      console.log(`Loaded ${callsData.length} calls and ${leadsData.length} leads from Supabase.`);
    } catch (err: any) {
      console.error("Failed to sync data:", err);
      setErrorMsg(err.message || "Failed to connect to Supabase. Please check your database tables exist and keys are correct.");
    } finally {
      setIsLoadingData(false);
    }
  };

  const handleUpdateLead = async (updatedLead: Lead) => {
    // Optimistic update
    setLeads(leads.map(l => l.id === updatedLead.id ? updatedLead : l));
    setSelectedLead(updatedLead);

    try {
      await updateLead(updatedLead);
    } catch (err) {
      console.error("Failed to save lead update to DB", err);
    }
  };

  const handleSyncCalls = () => {
    loadData();
    setCurrentView('calls');
  };

  const handleAddLeadPlaceholder = async () => {
    const newLead: Lead = {
      id: crypto.randomUUID(),
      firstName: 'New',
      lastName: 'Customer',
      email: '',
      phone: '',
      address: 'Enter address...',
      status: 'New',
      estimatedValue: 0,
      roofType: 'Unspecified',
      notes: [],
      createdAt: new Date().toISOString(),
      lastContact: new Date().toISOString()
    };

    setLeads([newLead, ...leads]);
    setSelectedLead(newLead);

    try {
      await createLead(newLead);
    } catch (err) {
      console.error("Failed to create lead in DB", err);
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 font-sans text-slate-900 overflow-hidden">

      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-20 md:hidden"
          onClick={() => setSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`fixed md:relative z-30 w-64 h-full bg-white border-r border-slate-200 flex flex-col transition-transform duration-300 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <div className="p-6 flex items-center justify-center border-b border-slate-100 h-24">
          <img 
            src="https://i.imgur.com/u1qL1C7.png" 
            alt="Kattoyksikkö IPM" 
            className="h-10 w-auto object-contain" 
          />
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2">
          <button 
            onClick={() => { setCurrentView('dashboard'); setSidebarOpen(false); }}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition duration-200 ${currentView === 'dashboard' ? 'bg-orange-600 text-white shadow-md shadow-orange-200' : 'text-slate-600 hover:bg-orange-50 hover:text-orange-700'}`}
          >
            <div className="flex items-center w-full justify-between">
              <div className="flex items-center space-x-3">
                <LayoutDashboard size={20} />
                <span className="font-medium">Dashboard</span>
              </div>
              {isLoadingData && <span className="w-2 h-2 bg-white rounded-full animate-pulse"></span>}
            </div>
          </button>

          <button 
            onClick={() => { setCurrentView('leads'); setSidebarOpen(false); }}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition duration-200 ${currentView === 'leads' ? 'bg-orange-600 text-white shadow-md shadow-orange-200' : 'text-slate-600 hover:bg-orange-50 hover:text-orange-700'}`}
          >
            <Users size={20} />
            <span className="font-medium">Leads</span>
          </button>

          <button 
            onClick={() => { setCurrentView('calls'); setSidebarOpen(false); }}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition duration-200 ${currentView === 'calls' ? 'bg-orange-600 text-white shadow-md shadow-orange-200' : 'text-slate-600 hover:bg-orange-50 hover:text-orange-700'}`}
          >
             <Phone size={20} />
             <span className="font-medium">Calls</span>
          </button>

          <button 
            onClick={() => { setCurrentView('settings'); setSidebarOpen(false); }}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition duration-200 ${currentView === 'settings' ? 'bg-orange-600 text-white shadow-md shadow-orange-200' : 'text-slate-600 hover:bg-orange-50 hover:text-orange-700'}`}
          >
            <Settings size={20} />
            <span className="font-medium">Settings</span>
          </button>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative bg-slate-50">
        {/* Top Header */}
        <header className="h-20 bg-white border-b border-slate-200 flex items-center justify-between px-6 shadow-sm z-10">
          <div className="flex items-center">
            <button 
              onClick={() => setSidebarOpen(true)}
              className="mr-4 p-2 rounded-lg hover:bg-slate-100 md:hidden"
            >
              <Menu size={24} className="text-slate-600" />
            </button>
            <h2 className="text-lg font-semibold text-slate-700 hidden sm:block">
              {currentView === 'dashboard' ? 'Overview' : 
               currentView === 'leads' ? 'Pipeline' : 
               currentView === 'calls' ? 'Call Activity' : 'Settings'}
            </h2>
          </div>

          <div className="flex items-center space-x-4">
             {errorMsg && (
                <div className="hidden lg:flex items-center text-red-600 text-xs bg-red-50 px-3 py-1 rounded-full border border-red-100 animate-pulse cursor-pointer hover:bg-red-100" title={errorMsg}>
                  <AlertCircle size={14} className="mr-1" />
                  Connection Error
                </div>
             )}
             <div className="relative hidden md:block">
               <input 
                  type="text" 
                  placeholder="Global search..." 
                  className="pl-9 pr-4 py-2 bg-slate-100 border-transparent focus:bg-white focus:ring-2 focus:ring-orange-500 rounded-full text-sm w-64 transition-all"
               />
               <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
             </div>
             <button className="p-2 relative rounded-full hover:bg-slate-100 text-slate-500 transition">
               <Bell size={20} />
               <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border border-white"></span>
             </button>
             <div className="w-8 h-8 rounded-full bg-orange-100 border border-orange-200 flex items-center justify-center text-orange-700 font-bold text-sm">
               JD
             </div>
          </div>
        </header>

        {/* View Content */}
        <div className="flex-1 overflow-auto p-4 md:p-8">
          {errorMsg && (
             <div className="mb-6 bg-red-50 border border-red-200 text-red-700 p-4 rounded-lg flex items-start">
               <AlertCircle size={20} className="mr-2 mt-0.5 flex-shrink-0" />
               <div>
                 <p className="font-bold">Database Connection Failed</p>
                 <p className="text-sm mt-1">{errorMsg}</p>
                 <p className="text-xs mt-2 text-red-500">Ensure your Supabase project keys are correct and the "leads" and "calls" tables exist.</p>
               </div>
             </div>
          )}

          {currentView === 'dashboard' && <Dashboard leads={leads} calls={calls} />}
          {currentView === 'leads' && (
            <LeadsBoard 
              leads={leads} 
              onSelectLead={setSelectedLead} 
              onAddLead={handleAddLeadPlaceholder}
            />
          )}
          {currentView === 'calls' && <CallsPage calls={calls} />}
          {currentView === 'settings' && <SettingsPage onSyncCalls={handleSyncCalls} />}
        </div>
      </main>

      {/* Modal Overlay for Lead Detail */}
      {selectedLead && (
        <LeadDetail 
          lead={selectedLead} 
          onClose={() => setSelectedLead(null)} 
          onUpdateLead={handleUpdateLead}
        />
      )}
    </div>
  );
}

export default App;

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';
import { DollarSign, HardHat, TrendingUp, AlertCircle, PhoneIncoming, Phone, PhoneMissed, PhoneOutgoing } from 'lucide-react';
