interface DashboardProps {
  leads: Lead[];
  calls: CallLog[];
}

// Updated color palette with Dark Orange as primary
const COLORS = ['#ea580c', '#3b82f6', '#10b981', '#f59e0b', '#8b5cf6', '#6366f1'];

export const Dashboard: React.FC<DashboardProps> = ({ leads, calls }) => {

  // --- Lead Analytics ---
  const totalPipelineValue = leads.reduce((acc, lead) => {
    return acc + (lead.status !== 'Lost' && lead.status !== 'Completed' ? lead.estimatedValue : 0);
  }, 0);

  const activeJobs = leads.filter(l => l.status === 'In Progress' || l.status === 'Scheduled').length;
  const completedJobs = leads.filter(l => l.status === 'Completed').length;

  // Lead Status Distribution
  const leadStatusCounts: Record<string, number> = {};
  leads.forEach(l => {
    leadStatusCounts[l.status] = (leadStatusCounts[l.status] || 0) + 1;
  });
  const leadStatusData = Object.keys(leadStatusCounts).map(status => ({
    name: status,
    value: leadStatusCounts[status]
  }));

  // Revenue Trend (based on Completed leads)
  const revenueByMonth: Record<string, number> = {};
  leads.forEach(l => {
    if (l.status === 'Completed' && l.estimatedValue > 0) {
      const date = new Date(l.lastContact); // Use lastContact as proxy for completion date
      if (!isNaN(date.getTime())) {
        const month = date.toLocaleString('default', { month: 'short' });
        revenueByMonth[month] = (revenueByMonth[month] || 0) + l.estimatedValue;
      }
    }
  });
  const revenueData = Object.keys(revenueByMonth).map(month => ({
    name: month,
    revenue: revenueByMonth[month]
  }));

  // --- Call Analytics ---
  const totalCalls = calls.length;
  const inboundCalls = calls.filter(c => c.type === 'Inbound').length;
  const outboundCalls = calls.filter(c => c.type === 'Outbound').length;
  const missedCalls = calls.filter(c => c.status === 'Voicemail' || c.status === 'Redirected').length;

  // Call Status Distribution
  const callStatusCounts: Record<string, number> = {};
  calls.forEach(c => {
    callStatusCounts[c.status] = (callStatusCounts[c.status] || 0) + 1;
  });
  const callStatusData = Object.keys(callStatusCounts).map(status => ({
    name: status,
    value: callStatusCounts[status]
  }));

  // Calls by Date (Trend)
  const callsByDate: Record<string, number> = {};
  calls.forEach(c => {
    const dateStr = c.date.split(' ')[0]; // Assuming format MM/DD/YYYY
    callsByDate[dateStr] = (callsByDate[dateStr] || 0) + 1;
  });

  // Sort and take last 10 entries for a clean chart
  const callTrendData = Object.keys(callsByDate)
    .sort((a,b) => new Date(a).getTime() - new Date(b).getTime())
    .slice(-10) 
    .map(date => ({
      name: date,
      calls: callsByDate[date]
    }));

  // --- Decision Logic: What to show? ---
  // If leads have no value, assume we are in "Call Log Mode"
  const hasValueData = leads.some(l => l.estimatedValue > 0);
  const hasStatusData = leads.some(l => l.status !== 'New' && l.status !== 'Contacted');
  const hasCallData = calls.length > 0;

  const showRevenueChart = hasValueData && revenueData.length > 0;
  const showCallTrendChart = !showRevenueChart && callTrendData.length > 0;

  const showLeadStatus = hasStatusData;
  const currentStatusData = showLeadStatus ? leadStatusData : callStatusData;

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold text-slate-800">Executive Dashboard</h1>
      </div>

      {/* Stats Grid: Adapts to available data */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">

        {/* Card 1: Total Calls (Always relevant) */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-indigo-100 rounded-full text-indigo-600">
            <Phone size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500">Total Calls</p>
            {hasCallData ? (
              <p className="text-2xl font-bold text-slate-800">{totalCalls}</p>
            ) : (
              <p className="text-sm font-medium text-slate-400 italic mt-1">No call data</p>
            )}
          </div>
        </div>

        {/* Card 2: Pipeline Value OR Inbound Calls */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-orange-100 rounded-full text-orange-600">
            {hasValueData ? <DollarSign size={24} /> : <PhoneIncoming size={24} />}
          </div>
          <div>
            <p className="text-sm text-slate-500">{hasValueData ? "Pipeline Value" : "Inbound Calls"}</p>
            {hasValueData ? (
              <p className="text-2xl font-bold text-slate-800">${totalPipelineValue.toLocaleString()}</p>
            ) : hasCallData ? (
               <p className="text-2xl font-bold text-slate-800">{inboundCalls}</p>
            ) : (
              <p className="text-sm font-medium text-slate-400 italic mt-1">--</p>
            )}
          </div>
        </div>

        {/* Card 3: Active Jobs OR Missed Calls */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-blue-100 rounded-full text-blue-600">
             {hasStatusData ? <HardHat size={24} /> : <PhoneMissed size={24} />}
          </div>
          <div>
            <p className="text-sm text-slate-500">{hasStatusData ? "Active Jobs" : "Missed/Voicemail"}</p>
            {hasStatusData ? (
              <p className="text-2xl font-bold text-slate-800">{activeJobs}</p>
            ) : hasCallData ? (
              <p className="text-2xl font-bold text-slate-800">{missedCalls}</p>
            ) : (
              <p className="text-sm font-medium text-slate-400 italic mt-1">--</p>
            )}
          </div>
        </div>

        {/* Card 4: Completed Jobs OR Outbound Calls */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-green-100 rounded-full text-green-600">
            {hasStatusData ? <TrendingUp size={24} /> : <PhoneOutgoing size={24} />}
          </div>
          <div>
            <p className="text-sm text-slate-500">{hasStatusData ? "Completed Jobs" : "Outbound Calls"}</p>
            {hasStatusData ? (
              <p className="text-2xl font-bold text-slate-800">{completedJobs}</p>
            ) : hasCallData ? (
              <p className="text-2xl font-bold text-slate-800">{outboundCalls}</p>
            ) : (
              <p className="text-sm font-medium text-slate-400 italic mt-1">--</p>
            )}
          </div>
        </div>
      </div>

      {/* Info Banner if LEAD data missing but CALL data exists */}
      {(!hasValueData && !hasStatusData && hasCallData) && (
        <div className="bg-orange-50 border border-orange-100 text-orange-800 p-4 rounded-lg flex items-start text-sm">
          <AlertCircle size={18} className="mr-2 mt-0.5 flex-shrink-0" />
          <div>
            <p className="font-semibold">Dashboard Mode: Call Analytics</p>
            <p>
              Revenue and Pipeline status were not found in your data, so we are displaying Call Volume analytics instead. 
            </p>
          </div>
        </div>
      )}

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

        {/* Chart 1: Status Distribution */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex flex-col">
          <h3 className="text-lg font-semibold mb-4 text-slate-700">
            {showLeadStatus ? "Lead Status Distribution" : "Call Outcome Distribution"}
          </h3>
          <div className="flex-1 min-h-[250px] relative">
            {(currentStatusData.length > 0) ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={currentStatusData}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                  >
                    {currentStatusData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="absolute inset-0 flex items-center justify-center text-slate-400">
                No data available
              </div>
            )}
          </div>
           <div className="flex flex-wrap justify-center gap-4 text-sm text-slate-600 mt-4">
            {currentStatusData.map((entry, index) => (
              <div key={entry.name} className="flex items-center">
                <div className="w-3 h-3 rounded-full mr-2" style={{ backgroundColor: COLORS[index % COLORS.length] }}></div>
                {entry.name} ({entry.value})
              </div>
            ))}
          </div>
        </div>

        {/* Chart 2: Trends */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex flex-col">
          <h3 className="text-lg font-semibold mb-4 text-slate-700">
            {showRevenueChart ? "Revenue Trend" : "Call Volume (Last 10 Activity Days)"}
          </h3>
          <div className="flex-1 min-h-[250px] relative">
            {showRevenueChart ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={revenueData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} />
                  <YAxis axisLine={false} tickLine={false} tickFormatter={(val) => `$${val/1000}k`} />
                  <Tooltip formatter={(val: number) => `$${val.toLocaleString()}`} cursor={{fill: 'transparent'}} />
                  <Bar dataKey="revenue" fill="#ea580c" radius={[4, 4, 0, 0]} barSize={40} />
                </BarChart>
              </ResponsiveContainer>
            ) : showCallTrendChart ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={callTrendData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} />
                  <YAxis axisLine={false} tickLine={false} allowDecimals={false} />
                  <Tooltip cursor={{fill: 'transparent'}} />
                  <Bar dataKey="calls" fill="#ea580c" radius={[4, 4, 0, 0]} barSize={40} />
                </BarChart>
              </ResponsiveContainer>
            ) : (
               <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-400 bg-slate-50/50 rounded-lg">
                <TrendingUp size={32} className="mb-2 opacity-20" />
                <p>Not enough data for Trend Chart.</p>
              </div>
            )}
          </div>
        </div>

      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Lead, LeadStatus } from '../types';
import { Search, Plus, Phone, MoreHorizontal } from 'lucide-react';

interface LeadsBoardProps {
  leads: Lead[];
  onSelectLead: (lead: Lead) => void;
  onAddLead: () => void; // Simple placeholder for add functionality
}

export const LeadsBoard: React.FC<LeadsBoardProps> = ({ leads, onSelectLead, onAddLead }) => {
  const [filter, setFilter] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('All');

  const filteredLeads = leads.filter(lead => {
    const matchesSearch = 
      lead.firstName.toLowerCase().includes(filter.toLowerCase()) || 
      lead.lastName.toLowerCase().includes(filter.toLowerCase()) ||
      lead.address.toLowerCase().includes(filter.toLowerCase());
    const matchesStatus = statusFilter === 'All' || lead.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const getStatusColor = (status: LeadStatus) => {
    switch(status) {
      case 'New': return 'bg-blue-100 text-blue-700';
      case 'Contacted': return 'bg-yellow-100 text-yellow-700';
      case 'Estimate Sent': return 'bg-purple-100 text-purple-700';
      case 'Scheduled': return 'bg-indigo-100 text-indigo-700';
      case 'In Progress': return 'bg-orange-100 text-orange-700';
      case 'Completed': return 'bg-green-100 text-green-700';
      case 'Lost': return 'bg-slate-100 text-slate-700';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  return (
    <div className="space-y-6 h-full flex flex-col animate-in fade-in duration-500">
      <div className="flex flex-col sm:flex-row justify-between items-center gap-4">
        <h1 className="text-3xl font-bold text-slate-800">Leads Management</h1>
        <button 
          onClick={onAddLead}
          className="bg-orange-600 hover:bg-orange-700 text-white px-4 py-2 rounded-lg flex items-center font-medium transition shadow-sm"
        >
          <Plus size={18} className="mr-2" />
          Add New Lead
        </button>
      </div>

      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-100 flex flex-col sm:flex-row gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={20} />
          <input 
            type="text" 
            placeholder="Search by name or address..." 
            className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-orange-500 outline-none"
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
          />
        </div>
        <select 
          className="p-2 border border-slate-200 rounded-lg bg-white outline-none focus:ring-2 focus:ring-orange-500 text-slate-600"
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
        >
          <option value="All">All Statuses</option>
          <option value="New">New</option>
          <option value="Contacted">Contacted</option>
          <option value="Estimate Sent">Estimate Sent</option>
          <option value="Scheduled">Scheduled</option>
          <option value="In Progress">In Progress</option>
          <option value="Completed">Completed</option>
          <option value="Lost">Lost</option>
        </select>
      </div>

      <div className="flex-1 overflow-auto bg-white rounded-xl shadow-sm border border-slate-100">
        <table className="w-full text-left border-collapse">
          <thead className="bg-slate-50 sticky top-0 z-10">
            <tr>
              <th className="p-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Name</th>
              <th className="p-4 text-xs font-semibold text-slate-500 uppercase tracking-wider">Status</th>
              <th className="p-4 text-xs font-semibold text-slate-500 uppercase tracking-wider hidden md:table-cell">Phone</th>
              <th className="p-4 text-xs font-semibold text-slate-500 uppercase tracking-wider hidden lg:table-cell">Address</th>
              <th className="p-4 text-xs font-semibold text-slate-500 uppercase tracking-wider text-right">Value</th>
              <th className="p-4 text-xs font-semibold text-slate-500 uppercase tracking-wider"></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {filteredLeads.length === 0 ? (
              <tr>
                <td colSpan={6} className="p-8 text-center text-slate-400">
                  No leads found matching your criteria.
                </td>
              </tr>
            ) : (
              filteredLeads.map((lead) => (
                <tr 
                  key={lead.id} 
                  onClick={() => onSelectLead(lead)}
                  className="hover:bg-orange-50 cursor-pointer transition duration-150 group"
                >
                  <td className="p-4">
                    <div className="font-medium text-slate-800">{lead.firstName} {lead.lastName}</div>
                    <div className="text-xs text-slate-500 md:hidden">{lead.phone}</div>
                  </td>
                  <td className="p-4">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${getStatusColor(lead.status)}`}>
                      {lead.status}
                    </span>
                  </td>
                  <td className="p-4 hidden md:table-cell text-slate-600 text-sm">
                    <div className="flex items-center">
                      <Phone size={14} className="mr-2 text-slate-400" />
                      {lead.phone}
                    </div>
                  </td>
                  <td className="p-4 hidden lg:table-cell text-slate-600 text-sm truncate max-w-xs">{lead.address}</td>
                  <td className="p-4 text-right font-medium text-slate-700">${lead.estimatedValue.toLocaleString()}</td>
                  <td className="p-4 text-right">
                    <button className="p-2 text-slate-400 hover:text-orange-600 rounded-full hover:bg-orange-100 transition">
                      <MoreHorizontal size={20} />
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Lead, Note, LeadStatus } from '../types';
import { X, Mail, Phone, Calendar, MapPin, Brain, Save, Send, Loader2, FileText } from 'lucide-react';
import { generateEmailDraft, summarizeLead } from '../services/geminiService';

interface LeadDetailProps {
  lead: Lead;
  onClose: () => void;
  onUpdateLead: (updatedLead: Lead) => void;
}

export const LeadDetail: React.FC<LeadDetailProps> = ({ lead, onClose, onUpdateLead }) => {
  const [activeTab, setActiveTab] = useState<'info' | 'notes' | 'ai'>('info');
  const [newNote, setNewNote] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiResponse, setAiResponse] = useState<string>('');
  const [aiActionType, setAiActionType] = useState<string>('');

  const handleStatusChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    onUpdateLead({ ...lead, status: e.target.value as LeadStatus });
  };

  const handleAddNote = () => {
    if (!newNote.trim()) return;
    const note: Note = {
      id: Date.now().toString(),
      content: newNote,
      date: new Date().toLocaleDateString(),
      author: 'You',
    };
    onUpdateLead({ ...lead, notes: [note, ...lead.notes] });
    setNewNote('');
  };

  const handleGenerateEmail = async (type: 'intro' | 'followup' | 'estimate' | 'closing') => {
    setIsGenerating(true);
    setAiActionType(`Generating ${type} email...`);
    const draft = await generateEmailDraft(lead, type);
    setAiResponse(draft);
    setIsGenerating(false);
  };

  const handleSummarize = async () => {
    setIsGenerating(true);
    setAiActionType('Summarizing lead...');
    const summary = await summarizeLead(lead);
    setAiResponse(summary);
    setIsGenerating(false);
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4 z-50 animate-in fade-in duration-200">
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl h-[90vh] flex flex-col overflow-hidden">

        {/* Header */}
        <div className="p-6 border-b border-slate-100 flex justify-between items-start bg-slate-50">
          <div>
            <h2 className="text-2xl font-bold text-slate-800">{lead.firstName} {lead.lastName}</h2>
            <div className="flex items-center text-slate-500 mt-1">
              <MapPin size={16} className="mr-1" />
              {lead.address}
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-200 rounded-full transition">
            <X size={24} className="text-slate-500" />
          </button>
        </div>

        <div className="flex flex-1 overflow-hidden">
          {/* Sidebar Info */}
          <div className="w-1/3 bg-slate-50 p-6 border-r border-slate-100 overflow-y-auto hidden md:block">
            <div className="space-y-6">
              <div>
                <label className="block text-xs font-semibold text-slate-400 uppercase tracking-wider mb-1">Status</label>
                <select 
                  value={lead.status} 
                  onChange={handleStatusChange}
                  className="w-full p-2 border border-slate-300 rounded-lg bg-white focus:ring-2 focus:ring-orange-500 outline-none"
                >
