                  <option value="Contacted">Contacted</option>
                  <option value="Estimate Sent">Estimate Sent</option>
                  <option value="Scheduled">Scheduled</option>
                  <option value="In Progress">In Progress</option>
                  <option value="Completed">Completed</option>
                  <option value="Lost">Lost</option>
                </select>
              </div>

              <div>
                <label className="block text-xs font-semibold text-slate-400 uppercase tracking-wider mb-1">Contact</label>
                <div className="flex items-center text-slate-700 mb-2">
                  <Mail size={16} className="mr-2 text-orange-600" />
                  <a href={`mailto:${lead.email}`} className="hover:underline text-sm truncate">{lead.email}</a>
                </div>
                <div className="flex items-center text-slate-700">
                  <Phone size={16} className="mr-2 text-orange-600" />
                  <span className="text-sm">{lead.phone}</span>
                </div>
              </div>

              <div>
                <label className="block text-xs font-semibold text-slate-400 uppercase tracking-wider mb-1">Project Details</label>
                <div className="bg-white p-3 rounded-lg border border-slate-200 space-y-2">
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-500">Value:</span>
                    <span className="font-semibold text-green-600">${lead.estimatedValue.toLocaleString()}</span>
                  </div>
                  <div className="flex justify-between text-sm">
                    <span className="text-slate-500">Roof Type:</span>
                    <span className="font-medium text-slate-700">{lead.roofType}</span>
                  </div>
                   <div className="flex justify-between text-sm">
                    <span className="text-slate-500">Last Contact:</span>
                    <span className="font-medium text-slate-700">{lead.lastContact}</span>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Main Content Area */}
          <div className="flex-1 flex flex-col bg-white">
            {/* Tabs */}
            <div className="flex border-b border-slate-100">
              <button 
