                  <div className="bg-orange-50 border border-orange-100 p-4 rounded-lg">
                    <h3 className="text-orange-800 font-semibold mb-2">Next Steps</h3>
                    <p className="text-sm text-orange-800">
                      This lead is currently in <span className="font-bold">{lead.status}</span> status. 
                      {lead.status === 'New' && " Consider generating an introduction email from the AI Assistant tab."}
