          </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { CallLog } from '../types';
import { Phone, PhoneIncoming, Clock, CheckCircle2, ArrowRightCircle, Voicemail } from 'lucide-react';

interface CallsPageProps {
  calls: CallLog[];
}

export const CallsPage: React.FC<CallsPageProps> = ({ calls }) => {
  // Filter for Inbound calls only
  const inboundCalls = calls.filter(c => c.type === 'Inbound');

  const totalInbound = inboundCalls.length;
  // AI Receptionist logic: 'Completed' usually means AI handled it.
  const aiHandledCalls = inboundCalls.filter(c => c.status === 'Completed' || c.status === 'Voicemail').length;
  const redirectedCalls = inboundCalls.filter(c => c.status === 'Redirected').length;

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'Completed': return <CheckCircle2 size={16} className="text-green-500" />;
      case 'Redirected': return <ArrowRightCircle size={16} className="text-orange-600" />;
      case 'Voicemail': return <Voicemail size={16} className="text-orange-600" />;
      default: return <Clock size={16} className="text-slate-400" />;
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <h1 className="text-3xl font-bold text-slate-800">Inbound Call Logs</h1>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-orange-100 rounded-full text-orange-600">
            <PhoneIncoming size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500">Total Inbound</p>
            <p className="text-2xl font-bold text-slate-800">{totalInbound}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-green-100 rounded-full text-green-600">
            <CheckCircle2 size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500">AI Handled</p>
            <p className="text-2xl font-bold text-slate-800">{aiHandledCalls}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-red-100 rounded-full text-red-600">
            <ArrowRightCircle size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500">Redirected</p>
            <p className="text-2xl font-bold text-slate-800">{redirectedCalls}</p>
          </div>
        </div>
      </div>

      {/* Calls List */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50">
          <h2 className="font-semibold text-slate-700">Recent Inbound Activity</h2>
        </div>
        <div className="divide-y divide-slate-100">
          {inboundCalls.length === 0 ? (
            <div className="p-8 text-center text-slate-400">
              No inbound calls recorded.
            </div>
          ) : (
            inboundCalls.map((call) => (
              <div key={call.id} className="p-4 hover:bg-slate-50 transition duration-150">
                <div className="flex flex-col md:flex-row justify-between md:items-start gap-4">
                  {/* Left Side: Icon & Basic Info */}
                  <div className="flex items-start space-x-4">
                    <div className="p-2 rounded-full mt-1 bg-orange-50 text-orange-600">
                      <PhoneIncoming size={20} />
                    </div>
                    <div>
                      <h3 className="font-medium text-slate-800">{call.leadName}</h3>
                      <div className="flex items-center text-xs text-slate-500 mt-1 space-x-2">
                        <span className="flex items-center">
                          <Clock size={12} className="mr-1" />
                          {call.date}
                        </span>
                        <span>•</span>
                        <span>{call.duration}</span>
                        <span>•</span>
                        <span className="flex items-center gap-1">
                          {getStatusIcon(call.status)}
                          {call.status}
                        </span>
                      </div>
                    </div>
                  </div>

                  {/* Right Side: Summary */}
                  <div className="flex-1 md:max-w-2xl bg-slate-50 p-3 rounded-lg border border-slate-100">
                    <p className="text-sm text-slate-600 leading-relaxed">
                      <span className="font-semibold text-slate-700 block text-xs uppercase tracking-wide mb-1">Summary</span>
                      {call.summary}
                    </p>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { LayoutDashboard, Users, Settings, Bell, Search, Menu, Phone, AlertCircle } from 'lucide-react';
import { Dashboard } from './components/Dashboard';
import { LeadsBoard } from './components/LeadsBoard';
import { LeadDetail } from './components/LeadDetail';
import { CallsPage } from './components/CallsPage';
import { SettingsPage } from './components/SettingsPage';
import { Lead, CallLog } from './types';
import { fetchLeads, fetchCalls, updateLead, createLead } from './services/supabaseService';

function App() {
  const [currentView, setCurrentView] = useState<'dashboard' | 'leads' | 'calls' | 'settings'>('dashboard');

  const [leads, setLeads] = useState<Lead[]>([]);
  const [calls, setCalls] = useState<CallLog[]>([]);

  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);
  const [isSidebarOpen, setSidebarOpen] = useState(false);
  const [isLoadingData, setIsLoadingData] = useState(false);
  const [errorMsg, setErrorMsg] = useState('');

  // Auto-load data from Supabase on mount
  useEffect(() => {
    loadData();
  }, []); 

  const loadData = async () => {
    setIsLoadingData(true);
    setErrorMsg('');
    try {
      const [leadsData, callsData] = await Promise.all([
        fetchLeads(),
        fetchCalls()
      ]);
      setLeads(leadsData);
      setCalls(callsData);
      console.log(`Loaded ${callsData.length} calls and ${leadsData.length} leads from Supabase.`);
    } catch (err: any) {
      console.error("Failed to sync data:", err);
      setErrorMsg(err.message || "Failed to connect to Supabase. Please check your database tables exist and keys are correct.");
    } finally {
      setIsLoadingData(false);
    }
  };

  const handleUpdateLead = async (updatedLead: Lead) => {
    // Optimistic update
    setLeads(leads.map(l => l.id === updatedLead.id ? updatedLead : l));
    setSelectedLead(updatedLead);

    try {
      await updateLead(updatedLead);
    } catch (err) {
      console.error("Failed to save lead update to DB", err);
    }
  };

  const handleSyncCalls = () => {
    loadData();
    setCurrentView('calls');
  };

  const handleAddLeadPlaceholder = async () => {
    const newLead: Lead = {
      id: crypto.randomUUID(),
      firstName: 'New',
      lastName: 'Customer',
      email: '',
      phone: '',
      address: 'Enter address...',
      status: 'New',
      estimatedValue: 0,
      roofType: 'Unspecified',
      notes: [],
      createdAt: new Date().toISOString(),
      lastContact: new Date().toISOString()
    };

    setLeads([newLead, ...leads]);
    setSelectedLead(newLead);

    try {
      await createLead(newLead);
    } catch (err) {
      console.error("Failed to create lead in DB", err);
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 font-sans text-slate-900 overflow-hidden">

      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-20 md:hidden"
          onClick={() => setSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`fixed md:relative z-30 w-64 h-full bg-white border-r border-slate-200 flex flex-col transition-transform duration-300 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <div className="p-6 flex items-center justify-center border-b border-slate-100 h-28">
           {/* Custom SVG Logo */}
           <svg viewBox="0 0 240 60" className="w-full h-full" xmlns="http://www.w3.org/2000/svg">
            <defs>
              <linearGradient id="roofGradient" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" style={{stopColor:'#374151', stopOpacity:1}} />
                <stop offset="100%" style={{stopColor:'#4b5563', stopOpacity:1}} />
              </linearGradient>
            </defs>

            {/* Sun */}
            <circle cx="185" cy="25" r="14" fill="#f97316" />
            <g stroke="#f97316" strokeWidth="3" strokeLinecap="round">
               <line x1="185" y1="6" x2="185" y2="2" />
               <line x1="185" y1="44" x2="185" y2="48" />
               <line x1="166" y1="25" x2="162" y2="25" />
               <line x1="204" y1="25" x2="208" y2="25" />
               <line x1="171.5" y1="11.5" x2="168.5" y2="8.5" />
               <line x1="198.5" y1="38.5" x2="201.5" y2="41.5" />
               <line x1="171.5" y1="38.5" x2="168.5" y2="41.5" />
               <line x1="198.5" y1="11.5" x2="201.5" y2="8.5" />
            </g>

            {/* Roof */}
            <path d="M10 38 L110 38 L85 15 L35 15 Z" fill="#374151" stroke="#1f2937" strokeWidth="2" />
            <path d="M85 15 L160 38 L170 38 L85 10 Z" fill="#4b5563" />

            {/* Window */}
            <rect x="45" y="22" width="16" height="16" fill="#cbd5e1" />
            <line x1="53" y1="22" x2="53" y2="38" stroke="#374151" strokeWidth="2" />
            <line x1="45" y1="30" x2="61" y2="30" stroke="#374151" strokeWidth="2" />

            {/* Text KATTO */}
            <text x="10" y="55" fontFamily="Arial, sans-serif" fontWeight="900" fontSize="24" fill="#374151" letterSpacing="-1" style={{fontStyle: 'italic'}}>KATTO</text>

            {/* Text YKSIKKÖ */}
            <text x="96" y="55" fontFamily="Arial, sans-serif" fontWeight="900" fontSize="24" fill="#f97316" letterSpacing="-1" style={{fontStyle: 'italic'}}>YKSIKKÖ</text>
          </svg>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2">
          <button 
            onClick={() => { setCurrentView('dashboard'); setSidebarOpen(false); }}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition duration-200 ${currentView === 'dashboard' ? 'bg-orange-600 text-white shadow-md shadow-orange-200' : 'text-slate-600 hover:bg-orange-50 hover:text-orange-700'}`}
          >
            <div className="flex items-center w-full justify-between">
