          <button 
            onClick={() => { setCurrentView('leads'); setSidebarOpen(false); }}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition duration-200 ${currentView === 'leads' ? 'bg-orange-600 text-white shadow-md shadow-orange-200' : 'text-slate-600 hover:bg-orange-50 hover:text-orange-700'}`}
