          <button 
            onClick={() => { setCurrentView('settings'); setSidebarOpen(false); }}
            className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition duration-200 ${currentView === 'settings' ? 'bg-orange-600 text-white shadow-md shadow-orange-200' : 'text-slate-600 hover:bg-orange-50 hover:text-orange-700'}`}
          >
            <Settings size={20} />
            <span className="font-medium">Settings</span>
          </button>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative bg-slate-50">
        {/* Top Header */}
        <header className="h-20 bg-white border-b border-slate-200 flex items-center justify-between px-6 shadow-sm z-10">
          <div className="flex items-center">
            <button 
              onClick={() => setSidebarOpen(true)}
              className="mr-4 p-2 rounded-lg hover:bg-slate-100 md:hidden"
            >
              <Menu size={24} className="text-slate-600" />
            </button>
            <h2 className="text-lg font-semibold text-slate-700 hidden sm:block">
              {currentView === 'dashboard' ? 'Overview' : 
               currentView === 'leads' ? 'Pipeline' : 
               currentView === 'calls' ? 'Call Activity' : 'Settings'}
            </h2>
          </div>

          <div className="flex items-center space-x-4">
             {errorMsg && (
                <div className="hidden lg:flex items-center text-red-600 text-xs bg-red-50 px-3 py-1 rounded-full border border-red-100 animate-pulse cursor-pointer hover:bg-red-100" title={errorMsg}>
                  <AlertCircle size={14} className="mr-1" />
                  Connection Error
                </div>
             )}
             <div className="relative hidden md:block">
               <input 
                  type="text" 
                  placeholder="Global search..." 
                  className="pl-9 pr-4 py-2 bg-slate-100 border-transparent focus:bg-white focus:ring-2 focus:ring-orange-500 rounded-full text-sm w-64 transition-all"
               />
               <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
             </div>
             <button className="p-2 relative rounded-full hover:bg-slate-100 text-slate-500 transition">
               <Bell size={20} />
               <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border border-white"></span>
             </button>
             <div className="w-8 h-8 rounded-full bg-orange-100 border border-orange-200 flex items-center justify-center text-orange-700 font-bold text-sm">
               JD
             </div>
          </div>
        </header>

        {/* View Content */}
        <div className="flex-1 overflow-auto p-4 md:p-8">
          {errorMsg && (
             <div className="mb-6 bg-red-50 border border-red-200 text-red-700 p-4 rounded-lg flex items-start">
               <AlertCircle size={20} className="mr-2 mt-0.5 flex-shrink-0" />
               <div>
                 <p className="font-bold">Database Connection Failed</p>
                 <p className="text-sm mt-1">{errorMsg}</p>
                 <p className="text-xs mt-2 text-red-500">Ensure your Supabase project keys are correct and the "leads" and "calls" tables exist.</p>
               </div>
             </div>
          )}

          {currentView === 'dashboard' && <Dashboard leads={leads} calls={calls} />}
          {currentView === 'leads' && (
            <LeadsBoard 
              leads={leads} 
              onSelectLead={setSelectedLead} 
              onAddLead={handleAddLeadPlaceholder}
            />
          )}
          {currentView === 'calls' && <CallsPage calls={calls} />}
          {currentView === 'settings' && <SettingsPage onSyncCalls={handleSyncCalls} />}
        </div>
      </main>

      {/* Modal Overlay for Lead Detail */}
      {selectedLead && (
        <LeadDetail 
          lead={selectedLead} 
          onClose={() => setSelectedLead(null)} 
          onUpdateLead={handleUpdateLead}
        />
      )}
    </div>
  );
}

