interface Review {
  id: number;
  name: string;
  rating: number;
  comment: string;
  date: string;
}

const ReviewsSection: React.FC = () => {
  const { t } = useLanguage();
  const [reviews, setReviews] = useState<Review[]>([
    { id: 1, name: 'Sanni K.', rating: 5, comment: 'Seinäjoen parhaat sushit ja aina tuore buffet!', date: '2024-01-10' },
    { id: 2, name: 'Mikko R.', rating: 4, comment: 'Mahtava valikoima ja ystävällinen palvelu.', date: '2024-01-12' }
  ]);

  const [showForm, setShowForm] = useState(false);
  const [name, setName] = useState('');
  const [comment, setComment] = useState('');
  const [rating, setRating] = useState(5);
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !comment) return;

    const newReview: Review = {
      id: Date.now(),
      name,
      comment,
      rating,
      date: new Date().toISOString().split('T')[0]
    };

    setReviews([newReview, ...reviews]);
    setSubmitted(true);
    setName('');
    setComment('');
    setRating(5);
    setTimeout(() => {
      setSubmitted(false);
      setShowForm(false);
    }, 3000);
  };

  return (
    <section id="reviews" className="py-24 bg-white overflow-hidden">
      <div className="container mx-auto px-4">
        <div className="text-center mb-12">
          <h2 className="text-3xl md:text-5xl font-black mb-6 uppercase text-stone-900 tracking-tight">
            {t('reviews.title')}
          </h2>
          <p className="text-stone-500 text-lg md:text-xl font-medium max-w-xl mx-auto mb-8">
            {t('reviews.desc')}
