          <div className="flex flex-wrap justify-center gap-4">
            <button 
              onClick={() => setShowForm(!showForm)}
              className="bg-orange-fuumi text-white px-8 py-4 rounded-2xl font-black text-lg shadow-xl hover:scale-105 transition-all"
            >
              {showForm ? 'Peruuta' : t('reviews.write')}
            </button>
            <a 
              href="https://www.google.com/maps/place/Fuumi+Sushi+%26+Wok/"
              target="_blank"
              rel="noopener noreferrer"
              className="bg-stone-900 text-white px-8 py-4 rounded-2xl font-black text-lg shadow-xl hover:scale-105 transition-all"
            >
              {t('reviews.btn')}
            </a>
          </div>
        </div>

        {showForm && (
          <div className="max-w-xl mx-auto bg-stone-50 p-8 rounded-[2rem] border border-stone-100 shadow-xl mb-12 animate-fade-in">
            {submitted ? (
              <div className="text-center py-8">
                <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                  <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
                </div>
                <h3 className="text-2xl font-black text-stone-900">{t('reviews.thanks')}</h3>
              </div>
            ) : (
              <form onSubmit={handleSubmit} className="space-y-6">
                <div>
                  <label className="block text-sm font-black uppercase text-stone-400 mb-2">{t('reviews.rating')}</label>
                  <div className="flex gap-2">
                    {[1, 2, 3, 4, 5].map((star) => (
                      <button
                        key={star}
                        type="button"
                        onClick={() => setRating(star)}
                        className={`text-3xl transition-transform hover:scale-110 ${star <= rating ? 'text-yellow-400' : 'text-stone-300'}`}
                      >
                        ★
                      </button>
                    ))}
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-black uppercase text-stone-400 mb-2">{t('reviews.name')}</label>
                  <input 
                    type="text" 
