              <div className="flex gap-1 mb-4">
                {[...Array(5)].map((_, i) => (
                  <svg key={i} className={`w-5 h-5 ${i < rev.rating ? 'text-yellow-400' : 'text-stone-200'} fill-current`} viewBox="0 0 20 20">
