    const newReview: Review = {
      id: Date.now(),
      name,
      comment,
      rating,
      date: new Date().toLocaleDateString('fi-FI')
    };

    setReviews([newReview, ...reviews]);
    setSubmitted(true);
    setName('');
    setComment('');
    setRating(0);

    setTimeout(() => {
      setSubmitted(false);
      setShowForm(false);
    }, 2500);
  };

  return (
    <section id="reviews" className="py-24 bg-white">
      <div className="container mx-auto px-4">
