                <button 
                  type="submit"
                  disabled={rating === 0}
                  className={`w-full py-6 rounded-2xl font-black text-2xl shadow-xl transition-all active:scale-95 ${rating > 0 ? 'bg-orange-fuumi text-white hover:bg-orange-600' : 'bg-stone-200 text-stone-400 cursor-not-allowed'}`}
