          {reviews.map((rev) => (
            <div key={rev.id} className="bg-stone-50 p-8 rounded-[2.5rem] border border-stone-100 shadow-sm hover:shadow-xl transition-all transform hover:-translate-y-1">
              <div className="flex gap-1 mb-6">
                {[...Array(5)].map((_, i) => (
                  <svg key={i} className={`w-6 h-6 ${i < rev.rating ? 'text-yellow-400' : 'text-stone-200'} fill-current`} viewBox="0 0 20 20">
