      navigator.clipboard.writeText(comment).catch(err => {
        console.error('Kopiointi epäonnistui: ', err);
      });
    }

    setSubmitted(true);

    // Ohjataan käyttäjä Googleen pienen viiveen jälkeen
    setTimeout(() => {
      window.open(CONTACT_DATA.googleReviewUrl, '_blank');
      setSubmitted(false);
      setName('');
      setComment('');
      setRating(0);
    }, 2000);
